me="action" value="edit_post" /><input type="hidden" name="post_id" value="<?php echo e($post['id'] ?? ''); ?>" /><input class="composer-input" name="title" value="<?php echo e($post['title'] ?? ''); ?>" /><textarea class="composer-input" name="content" rows="3"><?php echo e($post['content'] ?? ''); ?></textarea><input class="composer-input" name="category" value="<?php echo e($post['category'] ?? 'announcement'); ?>" /><input class="composer-input" type="date" name="deadline" value="<?php echo e($post['deadline'] ?? ''); ?>" /><div style="display:flex;gap:10px;justify-content:flex-end;"><button class="mini-btn" type="submit">Update</button></div></form><form action="../ActionController.php" method="post" style="display:flex;justify-content:flex-end;margin-top:8px;"><?php echo csrf_field(); ?><input type="hidden" name="action" value="delete_post" /><input type="hidden" name="post_id" value="<?php echo e($post['id'] ?? ''); ?>" /><button class="mini-btn danger" type="submit" onclick="return confirm('Delete this post?');">Delete</button></form></article><?php endforeach; ?></aside></div></div></div></main><footer class="portal-footer"><div class="footer-top-line"><span style="font-weight: 700;">SSC SEICT Management System</span><div class="footer-socials"><a href="#"><i class="fab fa-facebook"></i></a><a href="#"><i class="fab fa-twitter"></i></a><a href="#"><i class="fab fa-instagram"></i></a><a href="#"><i class="fab fa-youtube"></i></a></div></div><div class="footer-details d-flex justify-content-between flex-wrap" style="font-size: 0.85rem; opacity: 0.8;"><p>Don Toribio Street, Tetuan, Zamboanga City, 7000 Philippines | +63 917 894 6367 | universidaddezamboanga@uz.edu.ph</p><p>&copy; <?php echo date('Y'); ?> Universidad de Zamboanga. All rights reserved.</p></div></footer></body></html>
